import java.util.*;
public class QueueWith2Stacks {
    static class MyQueue {
        Deque<Integer> in=new ArrayDeque<>(),out=new ArrayDeque<>();
        void push(int x){in.push(x);}
        void pour(){if(out.isEmpty())while(!in.isEmpty())out.push(in.pop());}
        int pop(){pour();return out.pop();}
        int peek(){pour();return out.peek();}
        boolean empty(){return in.isEmpty()&&out.isEmpty();}
    }
    public static void main(String[] a){
        MyQueue q=new MyQueue();
        q.push(1);q.push(2);
        System.out.println(q.peek());  // 1
        System.out.println(q.pop());   // 1
        System.out.println(q.empty()); // false
        System.out.println("Amortized O(1) — each element poured at most once");
    }
}

import java.util.*;
public class StackWithQueue {
    static class MyStack {
        Deque<Integer> q=new ArrayDeque<>();
        void push(int x){q.offer(x);for(int i=1;i<q.size();i++)q.offer(q.poll());}
        int pop(){return q.poll();}
        int top(){return q.peek();}
        boolean empty(){return q.isEmpty();}
    }
    public static void main(String[] a){
        MyStack st=new MyStack();
        st.push(1);st.push(2);
        System.out.println(st.top());  // 2
        System.out.println(st.pop());  // 2
        System.out.println(st.empty()); // false
        System.out.println("O(n) push: rotate queue so new element is front");
    }
}

import java.util.*;
public class BFSTemplate {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    public static List<List<Integer>> levelOrder(TreeNode root) {
        List<List<Integer>> res=new ArrayList<>();
        if(root==null) return res;
        Queue<TreeNode> q=new ArrayDeque<>();q.offer(root);
        while(!q.isEmpty()){int size=q.size();List<Integer> level=new ArrayList<>();
            for(int i=0;i<size;i++){TreeNode node=q.poll();level.add(node.val);
                if(node.left!=null)q.offer(node.left);if(node.right!=null)q.offer(node.right);}
            res.add(level);}
        return res;
    }
    public static void main(String[] a){
        TreeNode root=new TreeNode(3);root.left=new TreeNode(9);root.right=new TreeNode(20);root.right.left=new TreeNode(15);root.right.right=new TreeNode(7);
        System.out.println(levelOrder(root)); // [[3],[9,20],[15,7]]
        System.out.println("size snapshot = number of current-level nodes");
    }
}

import java.util.*;
public class Islands {
    public static int numIslands(char[][] grid) {
        if(grid==null||grid.length==0) return 0;
        int rows=grid.length,cols=grid[0].length,islands=0;
        int[][] dirs={{0,1},{0,-1},{1,0},{-1,0}};
        for(int r=0;r<rows;r++) for(int c=0;c<cols;c++){
            if(grid[r][c]=='1'){islands++;
                Queue<int[]> q=new ArrayDeque<>();q.offer(new int[]{r,c});grid[r][c]='0';
                while(!q.isEmpty()){int[] pos=q.poll();for(int[] d:dirs){int nr=pos[0]+d[0],nc=pos[1]+d[1];if(nr>=0&&nr<rows&&nc>=0&&nc<cols&&grid[nr][nc]=='1'){grid[nr][nc]='0';q.offer(new int[]{nr,nc});}}}}}
        return islands;
    }
    public static void main(String[] a){
        System.out.println(numIslands(new char[][]{{'1','1','0'},{'0','1','0'},{'0','0','1'}})); // 2
        System.out.println(numIslands(new char[][]{{'1','1','1'},{'0','1','0'},{'1','1','1'}})); // 1
        System.out.println("O(m*n) BFS flooding approach");
    }
}

import java.util.*;
public class WallsGates {
    static final int INF=Integer.MAX_VALUE;
    public static void wallsAndGates(int[][] rooms) {
        int rows=rooms.length,cols=rooms[0].length;
        Queue<int[]> q=new ArrayDeque<>();
        int[][] dirs={{0,1},{0,-1},{1,0},{-1,0}};
        for(int r=0;r<rows;r++) for(int c=0;c<cols;c++) if(rooms[r][c]==0) q.offer(new int[]{r,c});
        while(!q.isEmpty()){int[] pos=q.poll();for(int[] d:dirs){int nr=pos[0]+d[0],nc=pos[1]+d[1];if(nr>=0&&nr<rows&&nc>=0&&nc<cols&&rooms[nr][nc]==INF){rooms[nr][nc]=rooms[pos[0]][pos[1]]+1;q.offer(new int[]{nr,nc});}}}
    }
    public static void main(String[] a){
        int[][] r={{INF,-1,0,INF},{INF,INF,INF,-1},{INF,-1,INF,-1},{0,-1,INF,INF}};
        wallsAndGates(r);System.out.println(Arrays.deepToString(r));
        System.out.println("Multi-source BFS from all gates simultaneously — O(m*n)");
    }
}

import java.util.*;
public class RottingOranges {
    public static int orangesRotting(int[][] grid) {
        int rows=grid.length,cols=grid[0].length,fresh=0,minutes=0;
        Queue<int[]> q=new ArrayDeque<>();int[][] dirs={{0,1},{0,-1},{1,0},{-1,0}};
        for(int r=0;r<rows;r++) for(int c=0;c<cols;c++){if(grid[r][c]==2)q.offer(new int[]{r,c});if(grid[r][c]==1)fresh++;}
        while(!q.isEmpty()&&fresh>0){minutes++;int size=q.size();for(int i=0;i<size;i++){int[] pos=q.poll();for(int[] d:dirs){int nr=pos[0]+d[0],nc=pos[1]+d[1];if(nr>=0&&nr<rows&&nc>=0&&nc<cols&&grid[nr][nc]==1){grid[nr][nc]=2;fresh--;q.offer(new int[]{nr,nc});}}}}
        return fresh==0?minutes:-1;
    }
    public static void main(String[] a){
        System.out.println(orangesRotting(new int[][]{{2,1,1},{1,1,0},{0,1,1}})); // 4
        System.out.println(orangesRotting(new int[][]{{2,1,1},{0,1,1},{1,0,1}})); // -1
        System.out.println("O(m*n) multi-source BFS with time tracking");
    }
}

import java.util.*;
public class PerfectSq {
    public static int numSquares(int n) {
        Queue<Integer> q=new ArrayDeque<>();q.offer(n); Set<Integer> seen=new HashSet<>();seen.add(n);
        int steps=0;
        while(!q.isEmpty()){steps++;int size=q.size();
            for(int i=0;i<size;i++){int curr=q.poll();for(int j=1;j*j<=curr;j++){int next=curr-j*j;if(next==0)return steps;if(!seen.contains(next)){seen.add(next);q.offer(next);}}}
        }
        return steps;
    }
    public static void main(String[] a){
        System.out.println(numSquares(12)); // 3 (4+4+4)
        System.out.println(numSquares(13)); // 2 (4+9)
        System.out.println("O(n*sqrt(n)) BFS — minimum steps = minimum perfect squares");
    }
}

import java.util.*;
public class QueueTypes {
    public static void main(String[] a){
        // Regular queue: FIFO
        Queue<Integer> fifo=new ArrayDeque<>();fifo.offer(3);fifo.offer(1);fifo.offer(2);
        System.out.println("FIFO poll: "+fifo.poll()); // 3 (insertion order)
        // Priority queue: min-heap by default
        PriorityQueue<Integer> pq=new PriorityQueue<>();pq.offer(3);pq.offer(1);pq.offer(2);
        System.out.println("Min-heap poll: "+pq.poll()); // 1 (smallest)
        // Max-heap:
        PriorityQueue<Integer> maxPQ=new PriorityQueue<>(Collections.reverseOrder());
        maxPQ.offer(3);maxPQ.offer(1);maxPQ.offer(2);
        System.out.println("Max-heap poll: "+maxPQ.poll()); // 3 (largest)
        System.out.println("ArrayDeque: O(1) FIFO. PriorityQueue: O(log n) heap ops");
    }
}

import java.util.*;
public class BFSSynth {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static List<List<Integer>> levelOrder(TreeNode root){List<List<Integer>> res=new ArrayList<>();if(root==null)return res;Queue<TreeNode> q=new ArrayDeque<>();q.offer(root);while(!q.isEmpty()){int sz=q.size();List<Integer> lvl=new ArrayList<>();for(int i=0;i<sz;i++){TreeNode n=q.poll();lvl.add(n.val);if(n.left!=null)q.offer(n.left);if(n.right!=null)q.offer(n.right);}res.add(lvl);}return res;}
    static int numIslands(char[][] g){int r=g.length,c=g[0].length,cnt=0;int[][] d={{0,1},{0,-1},{1,0},{-1,0}};for(int i=0;i<r;i++)for(int j=0;j<c;j++){if(g[i][j]=='1'){cnt++;Queue<int[]> q=new ArrayDeque<>();q.offer(new int[]{i,j});g[i][j]='0';while(!q.isEmpty()){int[] p=q.poll();for(int[] dd:d){int ni=p[0]+dd[0],nj=p[1]+dd[1];if(ni>=0&&ni<r&&nj>=0&&nj<c&&g[ni][nj]=='1'){g[ni][nj]='0';q.offer(new int[]{ni,nj});}}}}}return cnt;}
    public static void main(String[] a){TreeNode root=new TreeNode(1);root.left=new TreeNode(2);root.right=new TreeNode(3);System.out.println(levelOrder(root));System.out.println(numIslands(new char[][]{{'1','0','1'},{'0','1','0'},{'1','0','1'}}));System.out.println("BFS = Queue + size snapshot for levels");}
}

import java.util.*;
public class T3Final {
    static class MyQueue{Deque<Integer> in=new ArrayDeque<>(),out=new ArrayDeque<>();void push(int x){in.push(x);}void pour(){if(out.isEmpty())while(!in.isEmpty())out.push(in.pop());}int pop(){pour();return out.pop();}int peek(){pour();return out.peek();}boolean empty(){return in.isEmpty()&&out.isEmpty();}}
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static int levelCount(TreeNode root){if(root==null)return 0;Queue<TreeNode> q=new ArrayDeque<>();q.offer(root);int levels=0;while(!q.isEmpty()){int sz=q.size();for(int i=0;i<sz;i++){TreeNode n=q.poll();if(n.left!=null)q.offer(n.left);if(n.right!=null)q.offer(n.right);}levels++;}return levels;}
    public static void main(String[] a){
        MyQueue mq=new MyQueue();mq.push(1);mq.push(2);mq.push(3);
        System.out.println("QueueWith2Stacks: "+mq.pop()+","+mq.pop());
        TreeNode r=new TreeNode(1);r.left=new TreeNode(2);r.right=new TreeNode(3);r.left.left=new TreeNode(4);
        System.out.println("levelCount: "+levelCount(r));
        boolean ok=mq.pop()==3&&levelCount(r)==3;
        System.out.println("All pass: "+ok);
    }
}
